namespace sv_f9f86ff16f634b728d4b7811a6db5816.Services;

public enum Severity { Info, Warning, Critical }

public class NotificationItem
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public Severity Severity { get; set; }
    public bool IsRead { get; set; }
    public DateTime Timestamp { get; set; }
}

/// <summary>
/// Scoped service — one instance per circuit (per user) in Blazor Server.
/// All interactive islands on the same circuit share this instance.
/// </summary>
public class NotificationService
{
    private readonly List<NotificationItem> _notifications = new();
    private int _nextId = 1;

    public event Action? OnChange;

    public IReadOnlyList<NotificationItem> All => _notifications.AsReadOnly();

    public int UnreadCount => _notifications.Count(n => !n.IsRead);

    public IReadOnlyList<NotificationItem> RecentUnread =>
        _notifications.Where(n => !n.IsRead)
                      .OrderByDescending(n => n.Timestamp)
                      .Take(3)
                      .ToList();

    public void Add(string title, Severity severity)
    {
        _notifications.Insert(0, new NotificationItem
        {
            Id = _nextId++,
            Title = title,
            Severity = severity,
            IsRead = false,
            Timestamp = DateTime.Now
        });
        NotifyStateChanged();
    }

    public void MarkAsRead(int id)
    {
        var item = _notifications.FirstOrDefault(n => n.Id == id);
        if (item is not null)
        {
            item.IsRead = true;
            NotifyStateChanged();
        }
    }

    public void Dismiss(int id)
    {
        _notifications.RemoveAll(n => n.Id == id);
        NotifyStateChanged();
    }

    public void MarkAllRead()
    {
        foreach (var n in _notifications)
            n.IsRead = true;
        NotifyStateChanged();
    }

    private void NotifyStateChanged() => OnChange?.Invoke();
}

@using sv_f9f86ff16f634b728d4b7811a6db5816.Services
@inject NotificationService Notifications
@implements IDisposable

<a href="notifications" class="nav-link notification-bell" title="Notifications">
    <span class="bi bi-bell-fill-nav-menu" aria-hidden="true"></span>
    Notifications
    @if (Notifications.UnreadCount > 0)
    {
        <span class="badge bg-danger rounded-pill ms-1">@Notifications.UnreadCount</span>
    }
</a>

@code {
    protected override void OnInitialized()
    {
        Notifications.OnChange += HandleStateChange;
    }

    private async void HandleStateChange()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Notifications.OnChange -= HandleStateChange;
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using sv_f9f86ff16f634b728d4b7811a6db5816.Services
@inject NotificationService NotificationSvc
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h3>Notifications</h3>

<button class="btn btn-sm btn-outline-primary mb-3" @onclick="NotificationSvc.MarkAllRead"
        disabled="@(NotificationSvc.UnreadCount == 0)">
    Mark All Read
</button>

@if (NotificationSvc.All.Count == 0)
{
    <p class="text-muted">No notifications.</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Id</th>
                <th>Title</th>
                <th>Severity</th>
                <th>Status</th>
                <th>Timestamp</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in NotificationSvc.All)
            {
                <tr class="@(item.IsRead ? "" : "fw-bold")">
                    <td>@item.Id</td>
                    <td>@item.Title</td>
                    <td>
                        <span class="badge @GetSeverityClass(item.Severity)">@item.Severity</span>
                    </td>
                    <td>@(item.IsRead ? "Read" : "Unread")</td>
                    <td>@item.Timestamp.ToString("g")</td>
                    <td>
                        @if (!item.IsRead)
                        {
                            <button class="btn btn-sm btn-outline-success me-1"
                                    @onclick="() => NotificationSvc.MarkAsRead(item.Id)">
                                Mark Read
                            </button>
                        }
                        <button class="btn btn-sm btn-outline-danger"
                                @onclick="() => NotificationSvc.Dismiss(item.Id)">
                            Dismiss
                        </button>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    protected override void OnInitialized()
    {
        NotificationSvc.OnChange += HandleChange;
    }

    private async void HandleChange()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        NotificationSvc.OnChange -= HandleChange;
    }

    private static string GetSeverityClass(Severity s) => s switch
    {
        Severity.Info => "bg-info text-dark",
        Severity.Warning => "bg-warning text-dark",
        Severity.Critical => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/dashboard"
@rendermode InteractiveServer
@using sv_f9f86ff16f634b728d4b7811a6db5816.Services
@inject NotificationService NotificationSvc
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h3>Dashboard</h3>

<div class="card mb-4" style="max-width: 500px;">
    <div class="card-header">Recent Unread Notifications</div>
    <div class="card-body">
        @if (NotificationSvc.RecentUnread.Count == 0)
        {
            <p class="text-muted mb-0">All caught up!</p>
        }
        else
        {
            <ul class="list-group list-group-flush">
                @foreach (var item in NotificationSvc.RecentUnread)
                {
                    <li class="list-group-item d-flex justify-content-between align-items-center">
                        <span>
                            <span class="badge @GetSeverityClass(item.Severity) me-2">@item.Severity</span>
                            @item.Title
                        </span>
                        <button class="btn btn-sm btn-outline-danger"
                                @onclick="() => NotificationSvc.Dismiss(item.Id)">
                            Dismiss
                        </button>
                    </li>
                }
            </ul>
        }
    </div>
</div>

<p class="text-muted small">A new notification arrives every 15 seconds while you're on this page.</p>

@code {
    private Timer? _timer;
    private int _timerCount;
    private static readonly string[] SampleTitles =
    [
        "Server CPU spike detected",
        "New user signed up",
        "Deployment completed",
        "Disk space running low",
        "Payment processed",
        "Backup finished",
        "Certificate expiring soon"
    ];

    protected override void OnInitialized()
    {
        NotificationSvc.OnChange += HandleChange;
        _timer = new Timer(OnTimerElapsed, null, TimeSpan.FromSeconds(15), TimeSpan.FromSeconds(15));
    }

    private void OnTimerElapsed(object? state)
    {
        var title = SampleTitles[_timerCount % SampleTitles.Length];
        var severity = (Severity)(_timerCount % 3);
        _timerCount++;

        InvokeAsync(() =>
        {
            NotificationSvc.Add(title, severity);
            StateHasChanged();
        });
    }

    private async void HandleChange()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        _timer?.Dispose();
        NotificationSvc.OnChange -= HandleChange;
    }

    private static string GetSeverityClass(Severity s) => s switch
    {
        Severity.Info => "bg-info text-dark",
        Severity.Warning => "bg-warning text-dark",
        Severity.Critical => "bg-danger",
        _ => "bg-secondary"
    };
}

