+                    <li class="list-group-item d-flex justify-content-between align-items-center">
+                        <span>
+                            <span class="badge @GetSeverityClass(item.Severity) me-2">@item.Severity</span>
+                            @item.Title
+                        </span>
+                        <button class="btn btn-sm btn-outline-danger"
+                                @onclick="() => NotificationSvc.Dismiss(item.Id)">
+                            Dismiss
+                        </button>
+                    </li>
+                }
+            </ul>
+        }
+    </div>
+</div>
+
+<p class="text-muted small">A new notification arrives every 15 seconds while you're on this page.</p>
+
+@code {
+    private Timer? _timer;
+    private int _timerCount;
+    private static readonly string[] SampleTitles =
+    [
+        "Server CPU spike detected",
+        "New user signed up",
+        "Deployment completed",
+        "Disk space running low",
+        "Payment processed",
+        "Backup finished",
+        "Certificate expiring soon"
+    ];
+
+    protected override void OnInitialized()
+    {
+        NotificationSvc.OnChange += HandleChange;
+        _timer = new Timer(OnTimerElapsed, null, TimeSpan.FromSeconds(15), TimeSpan.FromSeconds(15));
+    }
+
+    private void OnTimerElapsed(object? state)
+    {
+        var title = SampleTitles[_timerCount % SampleTitles.Length];
+        var severity = (Severity)(_timerCount % 3);
+        _timerCount++;
+
+        InvokeAsync(() =>
+        {
+            NotificationSvc.Add(title, severity);
+            StateHasChanged();
+        });
+    }
+
+    private async void HandleChange()
+    {
+        await InvokeAsync(StateHasChanged);
+    }
+
+    public void Dispose()
+    {
+        _timer?.Dispose();
+        NotificationSvc.OnChange -= HandleChange;
+    }
+
+    private static string GetSeverityClass(Severity s) => s switch
+    {
+        Severity.Info => "bg-info text-dark",
+        Severity.Warning => "bg-warning text-dark",
+        Severity.Critical => "bg-danger",
+        _ => "bg-secondary"
+    };
+}
